import React, { useState } from "react";

import {
    Card,
    Input,
    Button,
    Typography,
    Space,
    Avatar,
    message,
    Tag
} from "antd";

import {
    VideoCameraOutlined,
    // UserOutlined,
    CopyOutlined,
    ThunderboltOutlined
} from "@ant-design/icons";

const { Title, Text } = Typography;

export default function Lobby({ onJoin }) {

    const [inputId, setInputId] = useState("");
    // const [username, setUsername] = useState("");

    const handleCreate = () => {
        const id = Math.random().toString(36).substring(2, 8);

        navigator.clipboard.writeText(id);

        message.success("Room ID copied");

        onJoin(id, true);
    };

    const handleJoin = () => {
        if (!inputId.trim()) {
            message.error("Enter Room ID");
            return;
        }

        onJoin(inputId.trim(), false);
    };

    return (
        <div className="lobby">

            <Card
                style={{
                    width: 400,
                    borderRadius: 22,
                    background: "rgba(255,255,255,0.08)",
                    backdropFilter: "blur(14px)",
                    border: "1px solid rgba(255,255,255,0.1)"
                }}
            >

                <Space
                    direction="vertical"
                    size="large"
                    style={{ width: "100%" }}
                >

                    <div style={{ textAlign: "center" }}>

                        <Avatar
                            size={80}
                            icon={<VideoCameraOutlined />}
                        />

                        <Title
                            level={2}
                            style={{
                                color: "white",
                                marginTop: 15,
                                marginBottom: 5
                            }}
                        >
                            Video Chat
                        </Title>

                        <Text style={{ color: "#d1d5db" }}>
                            Create or join meetings instantly
                        </Text>

                        <div style={{ marginTop: 15 }}>
                            <Tag color="blue">
                                <ThunderboltOutlined />
                                Fast Connection
                            </Tag>
                        </div>

                    </div>

                    {/* <Input
                        size="large"
                        placeholder="Enter your name"
                        prefix={<UserOutlined />}
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                    /> */}

                    <Button
                        type="primary"
                        size="large"
                        block
                        icon={<VideoCameraOutlined />}
                        onClick={handleCreate}
                    >
                        Create Meeting
                    </Button>

                    <div
                        style={{
                            textAlign: "center",
                            color: "#aaa",
                            fontSize: 13
                        }}
                    >
                        OR
                    </div>

                    <Input
                        size="large"
                        placeholder="Enter Room ID"
                        value={inputId}
                        onChange={(e) => setInputId(e.target.value)}
                        onKeyDown={(e) =>
                            e.key === "Enter" && handleJoin()
                        }
                    />

                    <Button
                        size="large"
                        block
                        icon={<CopyOutlined />}
                        onClick={handleJoin}
                        disabled={!inputId}
                    >
                        Join Meeting
                    </Button>

                </Space>

            </Card>

        </div>
    );
}