import React, { useEffect, useState } from "react";
import {
    Layout,
    Card,
    Row,
    Col,
    Button,
    Tag,
    Typography,
    Space,
    Avatar,
    Tooltip,
    Divider,
} from "antd";

import {
    AudioMutedOutlined,
    AudioOutlined,
    VideoCameraOutlined,
    VideoCameraAddOutlined,
    LogoutOutlined,
    UserOutlined,
    CheckCircleOutlined,
    LoadingOutlined,
    CloseCircleOutlined,
} from "@ant-design/icons";

import { useWebRTC } from "../hooks/useWebRTC";

const { Header, Content } = Layout;
const { Title, Text } = Typography;

export default function Meeting({ roomId, isInitiator, onLeave }) {
    const {
        localVideo,
        remoteVideo,
        status,
        participants,
        start,
        toggleMute,
        toggleVideo,
        leave,
    } = useWebRTC(roomId);

    const [muted, setMuted] = useState(false);
    const [videoOff, setVideoOff] = useState(false);

    useEffect(() => {
        start(isInitiator);
    }, []);

    const handleMute = () => {
        toggleMute();
        setMuted((m) => !m);
    };

    const handleVideo = () => {
        toggleVideo();
        setVideoOff((v) => !v);
    };

    const handleLeave = () => {
        leave();
        onLeave();
    };

    const getStatusTag = () => {
        switch (status) {
            case "connected":
                return (
                    <Tag color="success" icon={<CheckCircleOutlined />}>
                        Connected
                    </Tag>
                );

            case "connecting":
                return (
                    <Tag color="processing" icon={<LoadingOutlined />}>
                        Connecting
                    </Tag>
                );

            default:
                return (
                    <Tag color="error" icon={<CloseCircleOutlined />}>
                        Disconnected
                    </Tag>
                );
        }
    };

    return (
        <Layout
            style={{
                minHeight: "100vh",
                background: "#0f172a",
                padding: "20px",
            }}
        >
            <Header
                style={{
                    background: "#111827",
                    borderRadius: "16px",
                    marginBottom: "20px",
                    padding: "0 24px",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                }}
            >
                <div>
                    <Title level={3} style={{ color: "white", margin: 0 }}>
                        Video Meeting
                    </Title>

                    <Text style={{ color: "#cbd5e1" }}>
                        Room ID: <strong>{roomId}</strong>
                    </Text>
                </div>

                <Space size="middle">
                    {getStatusTag()}

                    <Tag color="blue">
                        {participants} Participant
                        {participants !== 1 ? "s" : ""}
                    </Tag>

                    <Avatar
                        size="large"
                        icon={<UserOutlined />}
                        style={{ backgroundColor: "#1677ff" }}
                    />
                </Space>
            </Header>

            <Content>
                <Row gutter={[20, 20]}>
                    <Col xs={24} lg={12}>
                        <Card
                            title="Your Video"
                            bordered={false}
                            style={{
                                borderRadius: "18px",
                                background: "#111827",
                            }}
                            bodyStyle={{ padding: "12px" }}
                        >
                            <video
                                ref={localVideo}
                                autoPlay
                                muted
                                playsInline
                                style={{
                                    width: "100%",
                                    height: "420px",
                                    borderRadius: "14px",
                                    background: "black",
                                    objectFit: "cover",
                                }}
                            />
                        </Card>
                    </Col>

                    <Col xs={24} lg={12}>
                        <Card
                            title="Remote User"
                            bordered={false}
                            style={{
                                borderRadius: "18px",
                                background: "#111827",
                            }}
                            bodyStyle={{ padding: "12px" }}
                        >
                            <video
                                ref={remoteVideo}
                                autoPlay
                                playsInline
                                style={{
                                    width: "100%",
                                    height: "420px",
                                    borderRadius: "14px",
                                    background: "black",
                                    objectFit: "cover",
                                }}
                            />
                        </Card>
                    </Col>
                </Row>

                <Divider />

                <div
                    style={{
                        display: "flex",
                        justifyContent: "center",
                        marginTop: "20px",
                    }}
                >
                    <Space size="large">
                        <Tooltip title={muted ? "Unmute" : "Mute"}>
                            <Button
                                type={muted ? "primary" : "default"}
                                danger={muted}
                                shape="circle"
                                size="large"
                                icon={
                                    muted ? (
                                        <AudioMutedOutlined />
                                    ) : (
                                        <AudioOutlined />
                                    )
                                }
                                onClick={handleMute}
                                style={{
                                    width: "60px",
                                    height: "60px",
                                }}
                            />
                        </Tooltip>

                        <Tooltip
                            title={
                                videoOff
                                    ? "Enable Video"
                                    : "Disable Video"
                            }
                        >
                            <Button
                                type={videoOff ? "primary" : "default"}
                                danger={videoOff}
                                shape="circle"
                                size="large"
                                icon={
                                    videoOff ? (
                                        <VideoCameraAddOutlined />
                                    ) : (
                                        <VideoCameraOutlined />
                                    )
                                }
                                onClick={handleVideo}
                                style={{
                                    width: "60px",
                                    height: "60px",
                                }}
                            />
                        </Tooltip>

                        <Tooltip title="Leave Meeting">
                            <Button
                                danger
                                type="primary"
                                shape="round"
                                size="large"
                                icon={<LogoutOutlined />}
                                onClick={handleLeave}
                            >
                                Leave Meeting
                            </Button>
                        </Tooltip>
                    </Space>
                </div>
            </Content>
        </Layout>
    );
}