import { useRef, useState, useCallback } from "react";
import { Client } from "@stomp/stompjs";

export function useWebRTC(roomId) {
    const [status, setStatus] = useState("idle");
    const [participants, setParticipants] = useState(0);

    const localVideo = useRef(null);
    const remoteVideo = useRef(null);
    const peerRef = useRef(null);
    const socketRef = useRef(null);
    const iceQueue = useRef([]);
    const isInitiator = useRef(false);

    const userId = useRef(Math.random().toString(36).substring(2));

    // ── helpers ──────────────────────────────────────────────────
    const sendSignal = useCallback((destination, body) => {
        socketRef.current?.publish({ destination, body: JSON.stringify(body) });
    }, []);

    // ── create RTCPeerConnection ──────────────────────────────────
    const createPeer = useCallback((stream) => {
        const peer = new RTCPeerConnection({
            iceServers: [
                { urls: ["stun:stun.l.google.com:19302", "stun:global.stun.twilio.com:3478"] },
            ],
        });

        stream.getTracks().forEach((track) => peer.addTrack(track, stream));

        peer.ontrack = (e) => {
            if (remoteVideo.current) remoteVideo.current.srcObject = e.streams[0];
        };

        peer.onicecandidate = ({ candidate }) => {
            if (candidate) {
                sendSignal(`/app/ice/${roomId}`, { candidate, sender: userId.current });
            }
        };

        peer.onconnectionstatechange = () => {
            const s = peer.connectionState;
            if (s === "connected") setStatus("connected");
            if (s === "failed" || s === "disconnected") setStatus("disconnected");
        };

        peerRef.current = peer;
        return peer;
    }, [roomId, sendSignal]);

    // ── send offer (called by first user when 2nd joins) ─────────
    const sendOffer = useCallback(async () => {
        const peer = peerRef.current;
        if (!peer || !socketRef.current?.connected) return;

        const offer = await peer.createOffer();
        await peer.setLocalDescription(offer);
        sendSignal(`/app/offer/${roomId}`, { sdp: offer, sender: userId.current });
    }, [roomId, sendSignal]);

    // ── STOMP subscriptions ───────────────────────────────────────
    const connectSocket = useCallback((peer) => {
        const protocol = window.location.protocol === "https:" ? "wss" : "ws";
        const host =
            window.location.protocol === "https:"
                ? window.location.host
                : `${window.location.hostname}:8081`;

        const client = new Client({
            brokerURL: `${protocol}://${host}/signal`,
            reconnectDelay: 5000,

            onConnect: () => {
                // announce join
                client.publish({
                    destination: "/app/join",
                    body: JSON.stringify({ roomId, userId: userId.current }),
                });

                // participant count → auto-offer when 2nd user arrives
                client.subscribe(`/topic/participants/${roomId}`, (msg) => {
                    const users = JSON.parse(msg.body);
                    setParticipants(users.length);

                    // First user (initiator) sends offer when 2nd user joins
                    if (users.length === 2 && isInitiator.current) {
                        sendOffer();
                    }
                });

                // receive offer → answer it
                client.subscribe(`/topic/offer/${roomId}`, async (msg) => {
                    const data = JSON.parse(msg.body);
                    if (data.sender === userId.current) return;

                    await peer.setRemoteDescription(data.sdp);

                    // flush queued ICE candidates
                    for (const c of iceQueue.current) await peer.addIceCandidate(c);
                    iceQueue.current = [];

                    const answer = await peer.createAnswer();
                    await peer.setLocalDescription(answer);
                    client.publish({
                        destination: `/app/answer/${roomId}`,
                        body: JSON.stringify({ sdp: answer, sender: userId.current }),
                    });
                });

                // receive answer
                client.subscribe(`/topic/answer/${roomId}`, async (msg) => {
                    const data = JSON.parse(msg.body);
                    if (data.sender === userId.current) return;
                    await peer.setRemoteDescription(data.sdp);
                });

                // ICE candidates
                client.subscribe(`/topic/ice/${roomId}`, async (msg) => {
                    const data = JSON.parse(msg.body);
                    if (data.sender === userId.current) return;
                    try {
                        if (peer.remoteDescription) {
                            await peer.addIceCandidate(data.candidate);
                        } else {
                            iceQueue.current.push(data.candidate);
                        }
                    } catch (e) {
                        console.error("ICE error:", e);
                    }
                });
            },
        });

        client.activate();
        socketRef.current = client;
    }, [roomId, sendOffer]);

    // ── start: get media → create peer → connect socket ──────────
    const start = useCallback(async (initiator = false) => {
        isInitiator.current = initiator;
        setStatus("connecting");

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
            if (localVideo.current) localVideo.current.srcObject = stream;

            const peer = createPeer(stream);
            connectSocket(peer);
        } catch (e) {
            console.error("Media error:", e);
            setStatus("error");
        }
    }, [createPeer, connectSocket]);

    // ── controls ──────────────────────────────────────────────────
    const toggleMute = useCallback(() => {
        localVideo.current?.srcObject?.getAudioTracks().forEach((t) => {
            t.enabled = !t.enabled;
        });
    }, []);

    const toggleVideo = useCallback(() => {
        localVideo.current?.srcObject?.getVideoTracks().forEach((t) => {
            t.enabled = !t.enabled;
        });
    }, []);

    const leave = useCallback(() => {
        sendSignal("/app/leave", { roomId, userId: userId.current });
        peerRef.current?.close();
        socketRef.current?.deactivate();
        localVideo.current?.srcObject?.getTracks().forEach((t) => t.stop());
        if (localVideo.current) localVideo.current.srcObject = null;
        if (remoteVideo.current) remoteVideo.current.srcObject = null;
        setStatus("idle");
        setParticipants(0);
    }, [roomId, sendSignal]);

    return {
        localVideo,
        remoteVideo,
        status,
        participants,
        start,
        toggleMute,
        toggleVideo,
        leave,
    };
}